int main(int argc, char **argv) {
    printf("WG size of kernel = %d \n", BLOCK_SIZE);

    int max_rows, max_cols, penalty;
    char *tempchar;

    if (argc >= 4) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
        tempchar = argv[3];
    } else {
        fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> <file>\n", argv[0]);
        fprintf(stderr, "\t<dimension>  - x and y dimensions\n");
        fprintf(stderr, "\t<penalty> - penalty(positive integer)\n");
        fprintf(stderr, "\t<file> - filename\n");
        exit(1);
    }

    if (max_rows % BLOCK_SIZE != 0) {
        fprintf(stderr, "The dimension values must be a multiple of %d\n", BLOCK_SIZE);
        exit(1);
    }

    max_rows += 1;
    max_cols += 1;

    int *reference = (int *)malloc(max_rows * max_cols * sizeof(int));
    int *input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    int *output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    srand(7);

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }

    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            reference[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    int worksize = max_cols - 1;
    int offset_r = 0, offset_c = 0;
    int block_width = worksize / BLOCK_SIZE;

    // Define macros for SCORE and REF for local arrays
#define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j) reference_l[(j) + (i) * BLOCK_SIZE]

    // Process upper-left matrix
    printf("Processing upper-left matrix\n");
    for (int blk = 1; blk <= worksize / BLOCK_SIZE; blk++) {
#pragma omp parallel num_threads(BLOCK_SIZE)
        {
            int tx = omp_get_thread_num();
            int bx = 0; // This loop iteration index
            bx = omp_get_thread_num() / BLOCK_SIZE; // Not used here, just placeholder

            // Each thread corresponds to tx
            // We simulate the kernel for each bx in [0, blk-1]
            // So we run the kernel body for each bx in parallel

            // But here, we run the kernel for all bx in [0, blk-1] sequentially
            // So we parallelize over tx only

            // So we run the kernel for each bx sequentially
        }
        // Instead, we run the kernel for each bx sequentially here
        for (int bx = 0; bx < blk; bx++) {
#pragma omp parallel num_threads(BLOCK_SIZE)
            {
                int tx = omp_get_thread_num();

                int base = offset_r * max_cols + offset_c;

                int b_index_x = bx;
                int b_index_y = blk - 1 - bx;

                int index = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (max_cols + 1);
                int index_n = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
                int index_w = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (max_cols);
                int index_nw = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

                // Local arrays for this thread team
                static int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
                static int reference_l[BLOCK_SIZE * BLOCK_SIZE];

                // Initialize local memory
#pragma omp barrier
                if (tx == 0) {
                    SCORE(tx, 0) = input_itemsets[index_nw + tx];
                }
#pragma omp barrier

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    reference_l[ty + tx * BLOCK_SIZE] = reference[index + max_cols * ty];
                }
#pragma omp barrier

                SCORE(tx + 1, 0) = input_itemsets[index_w + max_cols * tx];
#pragma omp barrier

                SCORE(0, tx + 1) = input_itemsets[index_n];
#pragma omp barrier

                for (int m = 0; m < BLOCK_SIZE; m++) {
                    if (m >= tx) {
                        int t_index_x = tx + 1;
                        int t_index_y = m - tx + 1;

                        SCORE(t_index_y, t_index_x) = maximum(
                            SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                            SCORE(t_index_y, t_index_x - 1) - penalty,
                            SCORE(t_index_y - 1, t_index_x) - penalty);
                    }
#pragma omp barrier
                }
#pragma omp barrier

                for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
                    if (m >= tx) {
                        int t_index_x = tx + BLOCK_SIZE - m;
                        int t_index_y = BLOCK_SIZE - tx;

                        SCORE(t_index_y, t_index_x) = maximum(
                            SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                            SCORE(t_index_y, t_index_x - 1) - penalty,
                            SCORE(t_index_y - 1, t_index_x) - penalty);
                    }
#pragma omp barrier
                }

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    input_itemsets[index + max_cols * ty] = SCORE(ty + 1, tx + 1);
                }
            }
        }
    }

    // Process lower-right matrix
    printf("Processing lower-right matrix\n");
    for (int blk = worksize / BLOCK_SIZE - 1; blk >= 1; blk--) {
        for (int bx = 0; bx < blk; bx++) {
#pragma omp parallel num_threads(BLOCK_SIZE)
            {
                int tx = omp_get_thread_num();

                int base = offset_r * max_cols + offset_c;

                int b_index_x = bx + block_width - blk;
                int b_index_y = block_width - bx - 1;

                int index = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (max_cols + 1);
                int index_n = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
                int index_w = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (max_cols);
                int index_nw = base + max_cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

                static int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
                static int reference_l[BLOCK_SIZE * BLOCK_SIZE];

#pragma omp barrier
                if (tx == 0) {
                    SCORE(tx, 0) = input_itemsets[index_nw];
                }
#pragma omp barrier

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    reference_l[ty + tx * BLOCK_SIZE] = reference[index + max_cols * ty];
                }
#pragma omp barrier

                SCORE(tx + 1, 0) = input_itemsets[index_w + max_cols * tx];
#pragma omp barrier

                SCORE(0, tx + 1) = input_itemsets[index_n];
#pragma omp barrier

                for (int m = 0; m < BLOCK_SIZE; m++) {
                    if (m >= tx) {
                        int t_index_x = tx + 1;
                        int t_index_y = m - tx + 1;

                        SCORE(t_index_y, t_index_x) = maximum(
                            SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                            SCORE(t_index_y, t_index_x - 1) - penalty,
                            SCORE(t_index_y - 1, t_index_x) - penalty);
                    }
#pragma omp barrier
                }

                for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
                    if (m >= tx) {
                        int t_index_x = tx + BLOCK_SIZE - m;
                        int t_index_y = BLOCK_SIZE - tx;

                        SCORE(t_index_y, t_index_x) = maximum(
                            SCORE(t_index_y - 1, t_index_x - 1) + REF(t_index_y - 1, t_index_x - 1),
                            SCORE(t_index_y, t_index_x - 1) - penalty,
                            SCORE(t_index_y - 1, t_index_x) - penalty);
                    }
#pragma omp barrier
                }

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    input_itemsets[index + ty * max_cols] = SCORE(ty + 1, tx + 1);
                }
            }
        }
    }

#undef SCORE
#undef REF

#ifdef TRACEBACK
    FILE *fpo = fopen("result.txt", "w");
    fprintf(fpo, "print traceback value CPU:\n");

    for (int i = max_rows - 2, j = max_rows - 2; i >= 0 && j >= 0;) {
        int nw, n, w, traceback;
        if (i == max_rows - 2 && j == max_rows - 2)
            fprintf(fpo, "%d ", input_itemsets[i * max_cols + j]);
        if (i == 0 && j == 0)
            break;
        if (i > 0 && j > 0) {
            nw = input_itemsets[(i - 1) * max_cols + j - 1];
            w = input_itemsets[i * max_cols + j - 1];
            n = input_itemsets[(i - 1) * max_cols + j];
        } else if (i == 0) {
            nw = n = LIMIT;
            w = input_itemsets[i * max_cols + j - 1];
        } else if (j == 0) {
            nw = w = LIMIT;
            n = input_itemsets[(i - 1) * max_cols + j];
        }

        int new_nw = nw + reference[i * max_cols + j];
        int new_w = w - penalty;
        int new_n = n - penalty;

        traceback = maximum(new_nw, new_w, new_n);
        if (traceback == new_nw)
            traceback = nw;
        if (traceback == new_w)
            traceback = w;
        if (traceback == new_n)
            traceback = n;

        fprintf(fpo, "%d ", traceback);

        if (traceback == nw) {
            i--;
            j--;
            continue;
        } else if (traceback == w) {
            j--;
            continue;
        } else if (traceback == n) {
            i--;
            continue;
        }
    }

    fclose(fpo);
#endif

    printf("Computation Done\n");

    free(reference);
    free(input_itemsets);
    free(output_itemsets);

    return 0;
}
